INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 1, 3001, 100, 2.1, -416.5, "ヤマト", "2030/01/01 14:59:59", 2, 130011, 3001100, 0.0, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 4, 3001, 101, 5.68, -416.5, "ヤマト", "2030/01/01 14:59:59", 2, 130011, 3001101, 0.0, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 1, 3001, 102, 0.0, -416.5, "ヤマト", "2030/01/01 14:59:59", 1, 130011, 3001102, 0.0, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 1, 3002, 100, 0.0, -416.5, "フブキ", "2030/01/01 14:59:59", 1, 130211, 3002100, 0.0, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 1, 3002, 101, 0.0, -416.5, "フブキ", "2030/01/01 14:59:59", 1, 130211, 3002101, 0.0, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 5, 3002, 102, 8.53, -416.5, "フブキ", "2030/01/01 14:59:59", 2, 130211, 3002102, 0.0, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 7, 3002, 103, 5.67, -416.5, "フブキ", "2030/01/01 14:59:59", 1, 130211, 3002103, 0.0, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 1, 3002, 104, 0.0, -416.5, "フブキ", "2030/01/01 14:59:59", 1, 130211, 3002104, 0.0, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 3, 3004, 300, 0.0, -416.5, "フブキ", "2030/01/01 14:59:59", 3, 130211, 3002300, 0.0, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 7, 3005, 301, 0.0, -416.5, "フブキ", "2030/01/01 14:59:59", 7, 130211, 3002400, 0.0, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 2, 3003, 200, 4.4, -416.5, "フブキ", "2030/01/01 14:59:59", 1, 130211, 3003200, 0.0, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 7, 3003, 201, 0.0, -416.5, "フブキ", "2030/01/01 14:59:59", 7, 130211, 3003201, 0.0, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 1, 3003, 202, 5.6, -416.5, "フブキ", "2030/01/01 14:59:59", 2, 130211, 3003202, 0.0, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪");
